using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for Person: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing: TryGetTypeInfo returns false instead of throwing
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"\nTryGetTypeInfo(Person): found={found}, type={info?.Type.Name}");

// Try a type whose metadata might not be resolvable (using a restricted resolver)
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // empty resolver chain
};

bool notFound = restrictedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? missing);
Console.WriteLine($"TryGetTypeInfo(Person) with empty resolver: found={notFound}, info={missing?.Type.Name ?? "(null)"}");

record Person(string Name, int Age);

